// Parse Gemini response and build v1 memo
const geminiResp = $input.first().json;
const inputData = $('Validate Input A').first().json;

// Gemini response structure: candidates[0].content.parts[0].text
let rawText = '';
try {
  rawText = geminiResp.candidates[0].content.parts[0].text;
} catch(e) {
  throw new Error('Unexpected Gemini response shape: ' + JSON.stringify(geminiResp).slice(0, 300));
}

// Strip markdown fences
if (rawText.includes('```')) {
  const parts = rawText.split('```');
  rawText = parts[1] || parts[0];
  if (rawText.startsWith('json')) rawText = rawText.slice(4);
}

let memo;
try {
  memo = JSON.parse(rawText.trim());
} catch(e) {
  throw new Error('Failed to parse Gemini memo JSON: ' + e.message + '\nRaw: ' + rawText.slice(0, 300));
}

memo.account_id = inputData.account_id;
memo.extracted_at = new Date().toISOString();
memo.version = 'v1';
memo.source = 'demo_call';

return [{ json: { memo, account_id: inputData.account_id } }];

// Parse Gemini updates response and merge into v2 memo
const geminiResp = $input.first().json;
const inputData = $('Validate Input B').first().json;

let rawText = '';
try {
  rawText = geminiResp.candidates[0].content.parts[0].text;
} catch(e) {
  throw new Error('Unexpected Gemini response shape: ' + JSON.stringify(geminiResp).slice(0, 300));
}

if (rawText.includes('```')) {
  const parts = rawText.split('```');
  rawText = parts[1] || parts[0];
  if (rawText.startsWith('json')) rawText = rawText.slice(4);
}

let extraction;
try {
  extraction = JSON.parse(rawText.trim());
} catch(e) {
  throw new Error('Failed to parse Gemini updates JSON: ' + e.message);
}

const v1_memo = inputData.v1_memo;
const updates = extraction.updates || {};
const changeReasons = extraction.change_reasons || {};
const newQuestions = extraction.new_questions || [];

function deepMerge(base, overrides) {
  const result = JSON.parse(JSON.stringify(base));
  for (const [key, val] of Object.entries(overrides)) {
    if (result[key] && typeof result[key] === 'object' && typeof val === 'object' && !Array.isArray(val)) {
      result[key] = deepMerge(result[key], val);
    } else if (Array.isArray(val) && Array.isArray(result[key])) {
      const merged = [...result[key]];
      for (const item of val) { if (!merged.includes(item)) merged.push(item); }
      result[key] = merged;
    } else { result[key] = val; }
  }
  return result;
}

function computeDiff(obj1, obj2, path = '') {
  const changes = [];
  const keys = new Set([...Object.keys(obj1), ...Object.keys(obj2)]);
  const skipKeys = new Set(['version', 'source', 'extracted_at']);
  for (const key of keys) {
    if (skipKeys.has(key)) continue;
    const fullPath = path ? `${path}.${key}` : key;
    if (!(key in obj1)) { changes.push({ field: fullPath, change_type: 'added', old: null, new: obj2[key] }); }
    else if (!(key in obj2)) { changes.push({ field: fullPath, change_type: 'removed', old: obj1[key], new: null }); }
    else if (typeof obj1[key] === 'object' && obj1[key] && typeof obj2[key] === 'object' && obj2[key] && !Array.isArray(obj1[key])) { changes.push(...computeDiff(obj1[key], obj2[key], fullPath)); }
    else if (JSON.stringify(obj1[key]) !== JSON.stringify(obj2[key])) { changes.push({ field: fullPath, change_type: 'modified', old: obj1[key], new: obj2[key] }); }
  }
  return changes;
}

const v2_memo = deepMerge(v1_memo, updates);
v2_memo.version = 'v2';
v2_memo.source = 'onboarding_call';
v2_memo.extracted_at = new Date().toISOString();

const existingQ = v2_memo.questions_or_unknowns || [];
for (const q of newQuestions) { if (!existingQ.includes(q)) existingQ.push(q); }
v2_memo.questions_or_unknowns = existingQ;

const changes = computeDiff(v1_memo, v2_memo);
for (const c of changes) { c.reason = changeReasons[c.field] || 'Updated during onboarding call'; }

const changelog = { account_id: inputData.account_id, generated_at: new Date().toISOString(), v1_source: 'demo_call', v2_source: 'onboarding_call', total_changes: changes.length, changes };

return [{ json: { v2_memo, changelog, account_id: inputData.account_id } }];

