const geminiResp = $input.first().json;
const memoData = $('Build Memo v1').first().json;

let systemPrompt = '';
try { systemPrompt = geminiResp.candidates[0].content.parts[0].text; }
catch(e) { throw new Error('Unexpected Gemini prompt response: ' + JSON.stringify(geminiResp).slice(0, 200)); }

const memo = memoData.memo;
const accountId = memoData.account_id;
const er = memo.emergency_routing_rules || {};
const primary = er.primary_contact || {};

const agentSpec = {
  agent_name: `${memo.company_name || 'Company'} - Clara v1`,
  version: 'v1', voice_style: 'professional, warm, calm',
  system_prompt: systemPrompt,
  key_variables: { company_name: memo.company_name, business_hours: memo.business_hours, office_address: memo.office_address, emergency_definitions: memo.emergency_definition || [], primary_emergency_contact: primary, timezone: (memo.business_hours || {}).timezone_iana, custom_greeting: memo.custom_greeting, ai_disclosure: memo.ai_disclosure_preference },
  tool_invocation_placeholders: [
    { function: 'transfer_call', description: 'Transfer call to specified phone number', parameters: { phone_number: 'string', reason: 'string' } },
    { function: 'end_call', description: 'End the call gracefully', parameters: { reason: 'string' } }
  ],
  call_transfer_protocol: { primary_number: primary.phone, transfer_order: er.order || [], timeout_seconds: er.timeout_seconds || 30, transfer_hold_message: memo.transfer_hold_message || 'Please hold while I connect you.' },
  fallback_protocol: { message: er.fallback || 'We are unable to connect you right now. Please leave your name and number.', collect_fields: ['caller_name', 'caller_phone', 'issue_summary'] },
  generated_at: new Date().toISOString()
};

const fs = require('fs');
const path = require('path');
const outDir = path.join(process.cwd(), 'outputs', 'accounts', accountId, 'v1');
fs.mkdirSync(outDir, { recursive: true });
fs.writeFileSync(path.join(outDir, 'account_memo.json'), JSON.stringify(memo, null, 2));
fs.writeFileSync(path.join(outDir, 'agent_spec.json'), JSON.stringify(agentSpec, null, 2));

return [{ json: { status: 'success', account_id: accountId, company_name: memo.company_name, output_dir: outDir, questions_or_unknowns: memo.questions_or_unknowns || [], memo, agent_spec: agentSpec } }];

const geminiResp = $input.first().json;
const mergeData = $('Build Memo v2 + Changelog').first().json;

let systemPrompt = '';
try { systemPrompt = geminiResp.candidates[0].content.parts[0].text; }
catch(e) { throw new Error('Unexpected Gemini prompt response: ' + JSON.stringify(geminiResp).slice(0, 200)); }

const v2_memo = mergeData.v2_memo;
const changelog = mergeData.changelog;
const accountId = mergeData.account_id;
const er = v2_memo.emergency_routing_rules || {};
const primary = er.primary_contact || {};

const agentSpec = {
  agent_name: `${v2_memo.company_name || 'Company'} - Clara v2`,
  version: 'v2', voice_style: 'professional, warm, calm',
  system_prompt: systemPrompt,
  key_variables: { company_name: v2_memo.company_name, business_hours: v2_memo.business_hours, office_address: v2_memo.office_address, emergency_definitions: v2_memo.emergency_definition || [], primary_emergency_contact: primary, timezone: (v2_memo.business_hours || {}).timezone_iana, custom_greeting: v2_memo.custom_greeting, ai_disclosure: v2_memo.ai_disclosure_preference },
  tool_invocation_placeholders: [
    { function: 'transfer_call', description: 'Transfer call to specified phone number', parameters: { phone_number: 'string', reason: 'string' } },
    { function: 'end_call', description: 'End the call gracefully', parameters: { reason: 'string' } }
  ],
  call_transfer_protocol: { primary_number: primary.phone, transfer_order: er.order || [], timeout_seconds: er.timeout_seconds || 30, transfer_hold_message: v2_memo.transfer_hold_message || 'Please hold while I connect you.' },
  fallback_protocol: { message: er.fallback || 'We are unable to connect you right now. Please leave your name and number.', collect_fields: ['caller_name', 'caller_phone', 'issue_summary'] },
  generated_at: new Date().toISOString()
};

const changes = changelog.changes || [];
const mdLines = [`# Changelog — ${accountId}`, `**Generated:** ${new Date().toUTCString()}`, `**Changes:** ${changes.length} field(s) updated from demo → onboarding`, '', '## Summary of Changes', ''];
if (changes.length === 0) { mdLines.push('_No changes detected._'); }
else { for (const c of changes) { mdLines.push(`### \`${c.field}\` (${c.change_type.toUpperCase()})`); mdLines.push(`- **Before:** ${JSON.stringify(c.old)}`); mdLines.push(`- **After:** ${JSON.stringify(c.new)}`); if (c.reason) mdLines.push(`- **Reason:** ${c.reason}`); mdLines.push(''); } }
const changelogMd = mdLines.join('\n');

const fs = require('fs');
const path = require('path');
const outDir = path.join(process.cwd(), 'outputs', 'accounts', accountId, 'v2');
fs.mkdirSync(outDir, { recursive: true });
fs.writeFileSync(path.join(outDir, 'account_memo.json'), JSON.stringify(v2_memo, null, 2));
fs.writeFileSync(path.join(outDir, 'agent_spec.json'), JSON.stringify(agentSpec, null, 2));
fs.writeFileSync(path.join(outDir, 'changelog.json'), JSON.stringify(changelog, null, 2));
fs.writeFileSync(path.join(outDir, 'changelog.md'), changelogMd);

return [{ json: { status: 'success', account_id: accountId, company_name: v2_memo.company_name, output_dir: outDir, total_changes: changelog.total_changes, questions_or_unknowns: v2_memo.questions_or_unknowns || [], v2_memo, agent_spec: agentSpec, changelog } }];
